#!/usr/bin/env node

'use strict';

const fs = require('fs');
const path = require('path');

// ── Parse arguments ──────────────────────────────────────────────────────────

const args = process.argv.slice(2);

if (args.includes('--help') || args.includes('-h')) {
  console.log(`
Usage: npx sync-chat [target-dir] [options]

  target-dir   Path to the project directory (default: current directory)

Options:
  --force, -f  Overwrite existing files
  --help,  -h  Show this help message
`);
  process.exit(0);
}

const force = args.includes('--force') || args.includes('-f');
const targetArg = args.find((a) => !a.startsWith('-'));
const target = targetArg
  ? path.resolve(process.cwd(), targetArg)
  : process.cwd();

// ── Files to install (relative paths inside templates/ → destination) ────────

const TEMPLATES_DIR = path.join(__dirname, '..', 'templates');

if (!fs.existsSync(TEMPLATES_DIR)) {
  console.error('Error: templates directory not found. The package may be corrupted.');
  process.exit(1);
}

const FILES = [
  '.github/hooks/sync-chat.json',
  '.cursor/hooks.json',
  'scripts/export.sh',
  'scripts/restore.sh',
];

// ── Helpers ───────────────────────────────────────────────────────────────────

function ensureDir(dir) {
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
}

function green(s) { return `\x1b[32m${s}\x1b[0m`; }
function yellow(s) { return `\x1b[33m${s}\x1b[0m`; }
function bold(s) { return `\x1b[1m${s}\x1b[0m`; }

// ── Main ──────────────────────────────────────────────────────────────────────

console.log(`\nInstalling sync-chat hooks into ${bold(target)}\n`);

if (!fs.existsSync(target)) {
  console.error(`Error: target directory does not exist: ${target}`);
  process.exit(1);
}

let installed = 0;
let skipped = 0;

for (const rel of FILES) {
  const src = path.join(TEMPLATES_DIR, rel);
  const dest = path.join(target, rel);

  ensureDir(path.dirname(dest));

  if (fs.existsSync(dest) && !force) {
    console.log(`  ${yellow('skip')}  ${rel}  (already exists, use --force to overwrite)`);
    skipped++;
    continue;
  }

  fs.copyFileSync(src, dest);

  // Make shell scripts executable
  if (rel.endsWith('.sh')) {
    const mode = fs.statSync(dest).mode | 0o111;
    fs.chmodSync(dest, mode);
  }

  console.log(`  ${green('write')} ${rel}`);
  installed++;
}

console.log('');

if (installed === 0 && skipped > 0) {
  console.log(`All files already exist. Run with ${bold('--force')} to overwrite.\n`);
